def solve(weight_percent_data, porosity_data, organic_carbon_data):
    volume_percent_data = {}

    for mineral, weight_percent in weight_percent_data.items():
        # Assuming a simple conversion for demonstration purposes
        volume_percent_data[mineral] = weight_percent * 0.6  # Example conversion factor

    # Integrate porosity and organic carbon into the final output
    results = {}
    for mineral in volume_percent_data:
        results[mineral] = {
            'volume_percent': volume_percent_data[mineral],
            'porosity': porosity_data.get(mineral, 0),
            'organic_carbon': organic_carbon_data.get(mineral, 0)
        }

    return results
